import{Logger}from '../shared/logger.js';const TAG='[CommandPalette]';const CommandType={NAVIGATION: 'navigation',ACTION: 'action',SETTING: 'setting',EXTERNAL: 'external'};const Category={PAGES: 'pages',ACTIONS: 'actions',SETTINGS: 'settings',TOOLS: 'tools',HELP: 'help'};const DEFAULT_COMMANDS=[{id: 'dashboard',title: 'Dashboard',description: 'Tổng quan marketing',type: CommandType.NAVIGATION,category: Category.PAGES,url: '/admin/dashboard.html',icon: '📊',keywords: ['tổng quan','dashboard','trang chính']},{id: 'pipeline',title: 'Pipeline',description: 'Quản lý dự án',type: CommandType.NAVIGATION,category: Category.PAGES,url: '/admin/pipeline.html',icon: '📋',keywords: ['dự án','pipeline','quản lý']},{id: 'analytics',title: 'Analytics',description: 'Phân tích AI',type: CommandType.NAVIGATION,category: Category.PAGES,url: '/admin/ai-analysis.html',icon: '📈',keywords: ['phân tích','analytics','AI','báo cáo']},{id: 'pricing',title: 'Pricing',description: 'Cấu hình giá',type: CommandType.NAVIGATION,category: Category.PAGES,url: '/admin/pricing.html',icon: '💰',keywords: ['giá','pricing','cấu hình']},{id: 'features',title: 'Features Demo',description: 'Demo tính năng',type: CommandType.NAVIGATION,category: Category.PAGES,url: '/admin/features-demo.html',icon: '🎨',keywords: ['demo','features','tính năng']},{id: 'new-project',title: 'Tạo dự án mới',description: 'Thêm dự án vào pipeline',type: CommandType.ACTION,category: Category.ACTIONS,action:()=>window.location.href='/admin/pipeline.html?action=new',icon: '➕',keywords: ['tạo','mới','project','dự án']},{id: 'dark-mode',title: 'Bật/tắt Dark Mode',description: 'Chuyển đổi giao diện sáng/tối',type: CommandType.ACTION,category: Category.ACTIONS,action:()=>window.Theme?.toggle(),icon: '🌙',keywords: ['dark','mode','giao diện','tối','sáng']},{id: 'export-data',title: 'Xuất dữ liệu',description: 'Export data ra CSV/Excel',type: CommandType.ACTION,category: Category.ACTIONS,action:()=>window.ExportUtils?.exportToCSV([]),icon: '📤',keywords: ['xuất','export','data','CSV','Excel']},{id: 'clear-cache',title: 'Xóa cache',description: 'Clear localStorage và session',type: CommandType.ACTION,category: Category.ACTIONS,action:()=>{localStorage.clear();sessionStorage.clear();location.reload();},icon: '🗑️',keywords: ['xóa','clear','cache','reload']},{id: 'profile',title: 'Hồ sơ',description: 'Quản lý thông tin cá nhân',type: CommandType.NAVIGATION,category: Category.SETTINGS,url: '/portal/customer/profile.html',icon: '👤',keywords: ['hồ sơ','profile','tài khoản']},{id: 'notifications',title: 'Thông báo',description: 'Quản lý thông báo',type: CommandType.NAVIGATION,category: Category.SETTINGS,url: '/admin/dashboard.html#notifications',icon: '🔔',keywords: ['thông báo','notifications','alerts']},{id: 'ai-generator',title: 'AI Content Generator',description: 'Tạo nội dung với AI',type: CommandType.NAVIGATION,category: Category.TOOLS,url: '/admin/ai-content.html',icon: '🤖',keywords: ['AI','content','generator','tạo nội dung']},{id: 'calendar',title: 'Lịch nội dung',description: 'Quản lý lịch đăng bài',type: CommandType.NAVIGATION,category: Category.TOOLS,url: '/admin/content-calendar.html',icon: '📅',keywords: ['lịch','calendar','content','đăng bài']},{id: 'help-tour',title: 'Hướng dẫn',description: 'Xem hướng dẫn sử dụng',type: CommandType.ACTION,category: Category.HELP,action:()=>window.HelpTour?.start(),icon: '❓',keywords: ['help','hướng dẫn','tour','guide']},{id: 'keyboard-shortcuts',title: 'Keyboard Shortcuts',description: 'Danh sách phím tắt',type: CommandType.ACTION,category: Category.HELP,action:()=>window.KeyboardShortcuts?.showHelp(),icon: '⌨️',keywords: ['keyboard','shortcuts','phím tắt']},{id: 'changelog',title: 'Changelog',description: 'Xem lịch sử thay đổi',type: CommandType.NAVIGATION,category: Category.HELP,url: '/CHANGELOG.md',icon: '📝',keywords: ['changelog','lịch sử','thay đổi']}];class CommandPalette{constructor(){this.commands=[...DEFAULT_COMMANDS];this.isOpen=false;this.selectedIndex=0;this.recentSearches=this.loadRecentSearches();this.element=null;this.input=null;this.results=null;this.init();}init(){Logger.info(TAG,'Initializing Command Palette...');this.createUI();this.bindEvents();this.registerKeyboardShortcut();Logger.info(TAG,`Initialized with ${this.commands.length}commands`);}createUI(){const container=document.createElement('div');container.className='command-palette-overlay';container.innerHTML=`<div class="command-palette"><div class="command-palette-header"><input type="text" class="command-palette-input" placeholder="Tìm kiếm lệnh,trang,hành động...(Ctrl+K)" aria-label="Search commands"><kbd class="command-palette-kbd">ESC</kbd></div><div class="command-palette-results"></div><div class="command-palette-footer"><span><kbd>↑↓</kbd>Di chuyển</span><span><kbd>Enter</kbd>Chọn</span><span><kbd>ESC</kbd>Đóng</span></div></div>`;document.body.appendChild(container);this.element=container.querySelector('.command-palette');this.input=container.querySelector('.command-palette-input');this.results=container.querySelector('.command-palette-results');this.renderResults(this.commands);}bindEvents(){this.input.addEventListener('input',(e)=>{this.search(e.target.value);});this.input.addEventListener('keydown',(e)=>{this.handleKeydown(e);});this.element.closest('.command-palette-overlay').addEventListener('click',(e)=>{if(e.target===e.currentTarget){this.close();}});this.element.addEventListener('click',(e)=>{e.stopPropagation();});}registerKeyboardShortcut(){document.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();this.toggle();}});}handleKeydown(e){const items=this.results.querySelectorAll('.command-item');switch(e.key){case 'ArrowDown': e.preventDefault();this.selectedIndex=Math.min(this.selectedIndex+1,items.length-1);this.updateSelection(items);break;case 'ArrowUp': e.preventDefault();this.selectedIndex=Math.max(this.selectedIndex-1,0);this.updateSelection(items);break;case 'Enter': e.preventDefault();const selectedItem=items[this.selectedIndex];if(selectedItem){this.select(selectedItem.dataset.id);}break;case 'Escape': e.preventDefault();this.close();break;}}updateSelection(items){items.forEach((item,index)=>{if(index===this.selectedIndex){item.classList.add('selected');item.scrollIntoView({block: 'nearest'});}else{item.classList.remove('selected');}});}search(query){const normalizedQuery=query.toLowerCase().trim();if(!normalizedQuery){this.renderResults(this.commands);return;}const scored=this.commands.map(cmd=>{let score=0;if(cmd.title.toLowerCase().includes(normalizedQuery)){score+=100;}if(cmd.description.toLowerCase().includes(normalizedQuery)){score+=50;}cmd.keywords.forEach(keyword=>{if(keyword.includes(normalizedQuery)){score+=30;}});if(normalizedQuery.length>=3){const categoryMatch=this.fuzzyMatch(normalizedQuery,cmd.title);if(categoryMatch)score+=20;}return{...cmd,score};}).filter(item=>item.score>0).sort((a,b)=>b.score-a.score);if(scored.length>0){this.saveRecentSearch(query);}this.renderResults(scored);}fuzzyMatch(query,text){const normalizedText=text.toLowerCase();let queryIndex=0;for(let i=0;i<normalizedText.length&&queryIndex<query.length;i++){if(normalizedText[i]===query[queryIndex]){queryIndex++;}}return queryIndex===query.length;}renderResults(results){if(results.length===0){this.results.innerHTML=`<div class="command-empty"><span class="empty-icon">🔍</span><p>Không tìm thấy kết quả</p><p class="empty-hint">Thử từ khóa khác</p></div>`;this.selectedIndex=-1;return;}const grouped=results.reduce((acc,cmd)=>{if(!acc[cmd.category]){acc[cmd.category]=[];}acc[cmd.category].push(cmd);return acc;},{});let html='';Object.keys(grouped).forEach(category=>{html+=`<div class="command-category-header">${this.getCategoryLabel(category)}</div>`;grouped[category].forEach((cmd,index)=>{html+=`<div class="command-item" data-id="${cmd.id}" data-index="${Object.values(grouped).flat().indexOf(cmd)}"><span class="command-icon">${cmd.icon}</span><div class="command-info"><span class="command-title">${this.highlight(cmd.title)}</span><span class="command-description">${cmd.description}</span></div>${cmd.type===CommandType.NAVIGATION ? `<span class="command-hint">↵</span>` : ''}</div>`;});});this.results.innerHTML=html;this.selectedIndex=0;this.updateSelection(this.results.querySelectorAll('.command-item'));}getCategoryLabel(category){const labels={[Category.PAGES]: 'Trang',[Category.ACTIONS]: 'Hành động',[Category.SETTINGS]: 'Cài đặt',[Category.TOOLS]: 'Công cụ',[Category.HELP]: 'Trợ giúp'};return labels[category]||category;}highlight(text){const query=this.input.value.toLowerCase();if(!query)return text;const index=text.toLowerCase().indexOf(query);if(index===-1)return text;return text.slice(0,index)+'<mark>'+text.slice(index,index+query.length)+'</mark>'+text.slice(index+query.length);}select(id){const command=this.commands.find(c=>c.id===id);if(!command)return;Logger.info(TAG,`Selected: ${command.title}`);this.saveRecentSearch(command.title);if(command.action){command.action();}else if(command.url){window.location.href=command.url;}this.close();}toggle(){if(this.isOpen){this.close();}else{this.open();}}open(){this.isOpen=true;this.element.closest('.command-palette-overlay').classList.add('open');this.input.value='';this.input.focus();this.selectedIndex=0;this.renderResults(this.commands);}close(){this.isOpen=false;this.element.closest('.command-palette-overlay').classList.remove('open');this.input.blur();}loadRecentSearches(){try{const stored=localStorage.getItem('sadec_recent_searches');return stored ? JSON.parse(stored): [];}catch{return [];}}saveRecentSearch(query){try{let searches=this.loadRecentSearches();searches=searches.filter(s=>s!==query);searches.unshift(query);searches=searches.slice(0,5);localStorage.setItem('sadec_recent_searches',JSON.stringify(searches));this.recentSearches=searches;}catch(error){Logger.warn(TAG,'Failed to save recent search:',error);}}addCommand(command){this.commands.push(command);Logger.info(TAG,`Added command: ${command.title}`);}removeCommand(id){const index=this.commands.findIndex(c=>c.id===id);if(index!==-1){this.commands.splice(index,1);Logger.info(TAG,`Removed command: ${id}`);}}destroy(){this.element?.remove();Logger.info(TAG,'Destroyed');}}class CommandPaletteElement extends HTMLElement{constructor(){super();this.attachShadow({mode: 'open'});}connectedCallback(){this.render();}render(){this.shadowRoot.innerHTML=`<style>:host{display: none;}</style><slot></slot>`;}}if(!customElements.get('command-palette')){customElements.define('command-palette',CommandPaletteElement);}const palette=new CommandPalette();window.CommandPalette=palette;if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>palette.init());}else{palette.init();}export{CommandPalette,CommandType,Category};export default palette;